// src/pages/ApplyLeave.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

export default function ApplyLeave({ setActivePage }) {
  const { applyLeave, getTeacherSlots, currentUser, staff } = useApp();
  const [form, setForm] = useState({ fromDate: '', toDate: '', reason: '' });
  const [preview, setPreview] = useState(null);
  const [submitted, setSubmitted] = useState(false);

  const handlePreview = () => {
    if (!form.fromDate || !form.toDate || !form.reason) {
      alert('Please fill all fields');
      return;
    }
    const slots = getTeacherSlots(currentUser.id, form.fromDate, form.toDate);
    setPreview(slots);
  };

  const handleSubmit = () => {
    applyLeave(currentUser.id, form.fromDate, form.toDate, form.reason);
    setSubmitted(true);
    setTimeout(() => setActivePage('My Leaves'), 2000);
  };

  if (submitted) {
    return (
      <div style={styles.container}>
        <div style={styles.successBox}>
          <div style={styles.successIcon}>🎉</div>
          <h2 style={styles.successTitle}>Leave Request Submitted!</h2>
          <p style={styles.successMsg}>
            Your leave request has been submitted. Free staff have been notified for substitute requests.
          </p>
          <p style={{ color: '#64748b', fontSize: 14 }}>Redirecting to My Leaves...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📝 Apply for Leave</h1>
      <p style={styles.subtitle}>Submit your leave request. Free staff will get notified automatically.</p>

      <div style={styles.card}>
        <div style={styles.row}>
          <div style={styles.formGroup}>
            <label style={styles.label}>From Date *</label>
            <input
              type="date"
              style={styles.input}
              value={form.fromDate}
              onChange={e => { setForm({ ...form, fromDate: e.target.value }); setPreview(null); }}
              min={new Date().toISOString().split('T')[0]}
            />
          </div>
          <div style={styles.formGroup}>
            <label style={styles.label}>To Date *</label>
            <input
              type="date"
              style={styles.input}
              value={form.toDate}
              onChange={e => { setForm({ ...form, toDate: e.target.value }); setPreview(null); }}
              min={form.fromDate || new Date().toISOString().split('T')[0]}
            />
          </div>
        </div>
        {/* APPLY LEAVE */}
      <div className="card center">
        <h2>Apply Leave</h2>
        <div className="form">
          <input
            type="text"
            placeholder="Staff Name"
            value={staffName}
            onChange={(e) => setFacuName(e.target.value)}
          />

          <select value={department} onChange={(e) => setDepartment(e.target.value)}>
            <option value="">Select Department</option>
            <option>First Year</option>
            <option>Second Year</option>
            <option>Third Year</option>
          </select>

          <select value={leaveType} onChange={(e) => setLeaveType(e.target.value)}>
            <option value="">Select Leave Type</option>
            <option>Medical Leave</option>
            <option>Casual Leave</option>
            <option>Duty Leave</option>
            <option>Personal Leave</option>
          </select>

          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
          />
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
          />

          <textarea
            placeholder="Reason"
            value={reason}
            onChange={(e) => setReason(e.target.value)}
          ></textarea>
        </div>
      </div>

        <div style={styles.formGroup}>
          <label style={styles.label}>Reason for Leave *</label>
          <textarea
            style={styles.textarea}
            rows={3}
            placeholder="Enter reason for leave..."
            value={form.reason}
            onChange={e => setForm({ ...form, reason: e.target.value })}
          />
        </div>

        <button style={styles.previewBtn} onClick={handlePreview}>
          🔍 Preview Affected Classes & Substitutes
        </button>
      </div>

      {preview && (
        <div style={styles.previewSection}>
          <h2 style={styles.previewTitle}>
            {preview.length === 0 ? '✅ No Classes Affected' : `📋 ${preview.length} Classes Affected`}
          </h2>

          {preview.length > 0 && (
            <div style={styles.slotGrid}>
              {preview.map((slot, i) => (
                <div key={i} style={styles.slotCard}>
                  <div style={styles.slotHeader}>
                    <span style={styles.slotDay}>{slot.day}, {slot.date}</span>
                    <span style={styles.slotPeriod}>Period {slot.period}</span>
                  </div>
                  <div style={styles.slotDetails}>
                    <span>🕐 {slot.time}</span>
                    <span>🏫 Class {slot.class}</span>
                  </div>
                  <div style={styles.subsSection}>
                    <div style={styles.subsLabel}>Available Free Teachers:</div>
                    {slot.freeTeachers.length === 0 ? (
                      <div style={styles.noSub}>⚠️ No free teacher available</div>
                    ) : (
                      <div style={styles.subsList}>
                        {slot.freeTeachers.slice(0, 3).map(t => (
                          <span key={t.id} style={styles.subChip}>✅ {t.name}</span>
                        ))}
                        {slot.freeTeachers.length > 3 && <span style={styles.moreChip}>+{slot.freeTeachers.length - 3} more</span>}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}

          <button style={styles.submitBtn} onClick={handleSubmit}>✅ Confirm & Submit Leave Request</button>
        </div>
      )}
    </div>
  );
}

